PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS game_events (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      game_id TEXT NOT NULL,
      player_id TEXT NOT NULL,
      event_type TEXT NOT NULL,
      point_value INTEGER NOT NULL,
      corrected_event_id INTEGER,
      raw_transcript TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP, assisted_event_id INTEGER,
      FOREIGN KEY (game_id) REFERENCES games(id),
      FOREIGN KEY (player_id) REFERENCES players(id)
    );
CREATE TABLE IF NOT EXISTS game_transcripts (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      game_id TEXT NOT NULL,
      raw_text TEXT NOT NULL,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP, acted_on TEXT,
      FOREIGN KEY (game_id) REFERENCES games(id)
    );
CREATE TABLE IF NOT EXISTS games (
      id TEXT PRIMARY KEY,
      location TEXT,
      start_time DATETIME DEFAULT CURRENT_TIMESTAMP,
      end_time DATETIME,
      status TEXT DEFAULT 'active',
      winning_team TEXT
    , last_failed_transcript TEXT, target_score INTEGER, scoring_mode TEXT DEFAULT '1s2s', live_transcript TEXT, notes TEXT);
CREATE TABLE IF NOT EXISTS mvp_votes (
      id TEXT PRIMARY KEY,
      season INTEGER NOT NULL,
      voter_player_id TEXT NOT NULL,
      pick_1_player_id TEXT NOT NULL,
      pick_2_player_id TEXT NOT NULL,
      pick_3_player_id TEXT NOT NULL,
      ip_address TEXT,
      user_agent TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      UNIQUE(season, voter_player_id),
      FOREIGN KEY (voter_player_id) REFERENCES players(id),
      FOREIGN KEY (pick_1_player_id) REFERENCES players(id),
      FOREIGN KEY (pick_2_player_id) REFERENCES players(id),
      FOREIGN KEY (pick_3_player_id) REFERENCES players(id)
    );
CREATE TABLE IF NOT EXISTS mvp_voting (
      season INTEGER PRIMARY KEY,
      closed_at DATETIME
    );
CREATE TABLE IF NOT EXISTS players (
      id TEXT PRIMARY KEY,
      name TEXT UNIQUE NOT NULL,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    , full_name TEXT, first_name TEXT, last_name TEXT, status TEXT DEFAULT 'active', aliases TEXT, notes TEXT, last_played_date TEXT, groupme_user_id TEXT, groupme_name TEXT, voice_name TEXT);
CREATE TABLE IF NOT EXISTS rosters (
      game_id TEXT NOT NULL,
      player_id TEXT NOT NULL,
      team TEXT NOT NULL,
      PRIMARY KEY (game_id, player_id),
      FOREIGN KEY (game_id) REFERENCES games(id),
      FOREIGN KEY (player_id) REFERENCES players(id)
    );
CREATE TABLE IF NOT EXISTS season_awards (
      season INTEGER NOT NULL,
      award_type TEXT NOT NULL,
      player_id TEXT NOT NULL,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      PRIMARY KEY (season, award_type),
      FOREIGN KEY (player_id) REFERENCES players(id)
    );
CREATE INDEX idx_events_game ON game_events(game_id, created_at);
CREATE INDEX idx_events_player ON game_events(player_id, event_type);
CREATE INDEX idx_mvp_votes_season ON mvp_votes(season);
COMMIT;
